mapper.sql:
WHERE d.company_id = #{companyId}

  AND d.document_type = #{documentType}


  AND d.partner_id = #{partnerId}


  AND d.document_status = #{documentStatus}


  AND (
      d.document_no LIKE CONCAT('%', #{keyword}, '%')
      OR tp.partner_name LIKE CONCAT('%', #{keyword}, '%')
      OR p.part_name LIKE CONCAT('%', #{keyword}, '%')
      OR p.model_name LIKE CONCAT('%', #{keyword}, '%')
      OR p.part_code LIKE CONCAT('%', #{keyword}, '%')
  )

WHERE u.company_id = #{companyId} AND u.active = TRUE AND u.unit_status = 'IN_STOCK' AND u.inspection_status = 'COMPLETED' AND u.sales_status = 'AVAILABLE' AND u.grade != 'DEFECTIVE'
AND p.category_id = #{categoryId}
AND p.part_id = #{partId}
AND u.grade = #{grade}
AND ( u.internal_serial_no LIKE CONCAT('%', #{keyword}, '%') OR u.manufacturer_serial_no LIKE CONCAT('%', #{keyword}, '%') OR p.part_name LIKE CONCAT('%', #{keyword}, '%') OR p.model_name LIKE CONCAT('%', #{keyword}, '%') OR p.manufacturer LIKE CONCAT('%', #{keyword}, '%') OR p.part_code LIKE CONCAT('%', #{keyword}, '%') OR c.category_name LIKE CONCAT('%', #{keyword}, '%') )

mapper.select:
SELECT u.unit_id, u.internal_serial_no, u.manufacturer_serial_no, p.part_id, p.category_id, c.category_name, p.part_name, p.model_name, p.manufacturer, p.part_code, u.unit_status, u.inspection_status, u.grade, u.sales_status FROM tb_pc_part_unit u JOIN tb_pc_part p ON p.company_id = u.company_id AND p.part_id = u.part_id JOIN tb_part_category c ON c.company_id = p.company_id AND c.category_id = p.category_id WHERE u.company_id = #{companyId} AND u.part_id = #{partId} AND u.unit_id IN
#{unitId}
AND u.active = TRUE AND u.unit_status = 'IN_STOCK' AND u.inspection_status = 'COMPLETED' AND u.sales_status = 'AVAILABLE' AND u.grade != 'DEFECTIVE' ORDER BY u.unit_id FOR UPDATE

mapper.update:
UPDATE tb_stock_document
SET document_status = #{documentStatus}
WHERE company_id = #{companyId}
  AND document_id = #{documentId}

UPDATE tb_stock_movement
SET movement_status = #{movementStatus}
WHERE company_id = #{companyId}
  AND document_id = #{documentId}
  AND canceled_movement_id IS NULL

