mapper.update:
UPDATE tb_part_stock
SET quantity = #{quantity}
WHERE company_id = #{companyId}
  AND part_id = #{partId}

UPDATE tb_pc_part_unit
SET unit_status = 'CANCELED',
    active = FALSE
WHERE company_id = #{companyId}
  AND unit_id = #{unitId}

UPDATE tb_pc_part_unit
SET unit_status = 'OUTBOUND'
WHERE company_id = #{companyId}
  AND unit_id = #{unitId}

UPDATE tb_pc_part_unit
SET unit_status = 'IN_STOCK'
WHERE company_id = #{companyId}
  AND unit_id = #{unitId}
